SELECT

FROM common_user u
LEFT JOIN common_dept d ON u.dept_key = d.dept_key
LEFT JOIN common_position p ON u.position_key = p.position_key
WHERE 1=1

    AND u.user_name LIKE '%' || #{userName} || '%'


    AND u.dept_key = #{deptKey}


    AND u.use_yn = #{useYn}


    AND u.author_cd = #{authorCd}

mapper.update:
UPDATE common_user
dept_key = #{deptKey}, position_key = #{positionKey}, user_name = #{userName}, user_name_en = #{userNameEn}, user_comment = #{userComment}, email = #{email}, mobile_tel = #{mobileTel}, birth_date = #{birthDate}, use_yn = #{useYn}, user_password = #{userPassword}, user_type = #{userType}, author_cd = #{authorCd}, mod_date = CURRENT_TIMESTAMP, mod_user_key = #{modUserKey}
WHERE user_key = #{userKey}
